target AS (
  SELECT fl.id AS flock_id, COALESCE(fl.laying_farm_id, fl.rearing_farm_id) AS farm_id
  FROM flocks fl WHERE fl.flock_no = 21 AND fl.is_vhl_contract = true
)
INSERT INTO vhl_daily_entry (flock_id, shed_id, record_date, opening_female, opening_male,
  received_female, received_male, trcull_female, trcull_male, mortality_female, mortality_male,
  closing_female, closing_male, feed_female_kg, feed_male_kg, total_eggs, he_eggs,
  je_eggs, te_eggs, be_eggs, le_eggs, age_weeks, lighting_hrs)
SELECT t.flock_id, sh.id, v.record_date, v.opening_female, v.opening_male,
  v.received_female, v.received_male, v.trcull_female, v.trcull_male, v.mortality_female, v.mortality_male,
  v.closing_female, v.closing_male, v.feed_female_kg, v.feed_male_kg, v.total_eggs, v.he_eggs,
  v.je_eggs, v.te_eggs, v.be_eggs, v.le_eggs, v.age_weeks, v.lighting_hrs
FROM v JOIN target t ON true
JOIN sheds sh ON sh.farm_id = t.farm_id AND sh.shed_no = 4
ON CONFLICT (flock_id, record_date, shed_id) WHERE shed_id IS NOT NULL DO UPDATE SET
  opening_female=EXCLUDED.opening_female, opening_male=EXCLUDED.opening_male,
  received_female=EXCLUDED.received_female, received_male=EXCLUDED.received_male,
  trcull_female=EXCLUDED.trcull_female, trcull_male=EXCLUDED.trcull_male,
  mortality_female=EXCLUDED.mortality_female, mortality_male=EXCLUDED.mortality_male,
  closing_female=EXCLUDED.closing_female, closing_male=EXCLUDED.closing_male,
  feed_female_kg=EXCLUDED.feed_female_kg, feed_male_kg=EXCLUDED.feed_male_kg,
  total_eggs=EXCLUDED.total_eggs, he_eggs=EXCLUDED.he_eggs,
  je_eggs=EXCLUDED.je_eggs, te_eggs=EXCLUDED.te_eggs, be_eggs=EXCLUDED.be_eggs, le_eggs=EXCLUDED.le_eggs,
  age_weeks=EXCLUDED.age_weeks, lighting_hrs=EXCLUDED.lighting_hrs;

